import styled from "styled-components";

export const Banner = styled.div`
  min-width: 100vw;
  height: 18vh;  
  display:flex;
  align-items: center;
  justify-content: center;
  top: 0;
  opacity: .95;
  background-image: url("/img/WomansRightQuiltjpg.jpg");
  
  background-repeat: no-repeat;

`;
